# validator.py

# Load known city name set
KNOWN_CITIES = {
  'beijing', 'shanghai', 'guangzhou', ...
  # 80+ cities across China, Japan, Korea, SE Asia, Taiwan, Europe, Americas, Oceania
}

# Date regex: YYYY-MM-DD
_DATE_RE = re.compile(r'^\d{4}-\d{2}-\d{2}$')

def validate(inp: TravelInput) -> TravelOutput:
    errors: list[str] = []

    # 1. origin_city non-empty and known
    if not inp.origin_city or not inp.origin_city.strip():
        errors.append('origin_city is required')
    if not city_known(inp.origin_city):
        return _fail(CITY_NOT_FOUND, f"Unknown origin city: {inp.origin_city}")

    # 2. origin coordinates in range
    if not in_range(inp.origin_lat, (-90, 90)):
        errors.append(f'origin_lat out of range')
    if not in_range(inp.origin_lng, (-180, 180)):
        errors.append(f'origin_lng out of range')

    # 3. parse and validate start_date / end_date
    start = parse_date(inp.start_date)
    end   = parse_date(inp.end_date)
    if start is None:
        return _fail(INVALID_DATE, 'Invalid start_date format')
    if end is None:
        return _fail(INVALID_DATE, 'Invalid end_date format')
    if end <= start:
        return _fail(INVALID_DATE, 'end_date must be after start_date')
    if start < today():
        return _fail(DATE_IN_PAST, 'start_date is in the past')

    # 4. budget positive
    if inp.budget <= 0:
        return _fail(INVALID_BUDGET, 'budget must be positive')

    # 5. at least one stop
    if not inp.stops:
        return _fail(EMPTY_STOPS, 'At least one stop is required')

    # 6. validate each stop
    for i, stop in enumerate(inp.stops):
        if not stop.city or not stop.city.strip():
            return _fail(CITY_NOT_FOUND, f'stop[{i}]: city required')
        if not city_known(stop.city):
            return _fail(CITY_NOT_FOUND, f'stop[{i}]: Unknown city')
        if not in_range(stop.lat, (-90,90)):
            return _fail(INVALID_CITY, f'stop[{i}].lat out of range')
        if not in_range(stop.lng, (-180,180)):
            return _fail(INVALID_CITY, f'stop[{i}].lng out of range')
        arr = parse_date(stop.arrival_date)
        dep = parse_date(stop.departure_date)
        if arr is None or dep is None or dep <= arr:
            return _fail(INVALID_DATE, f'stop[{i}]: invalid dates')

    # 7. preference is Preference enum
    if not isinstance(inp.preference, Preference):
        return _fail(INVALID_PREFERENCE, 'Invalid preference')

    # 8. all transport_modes are TransportMode enum
    for mode in inp.transport_modes:
        if not isinstance(mode, TransportMode):
            return _fail(UNSUPPORTED_TRANSPORT, f'Unsupported mode: {mode}')

    # 9. currency is Currency enum
    if not isinstance(inp.currency, Currency):
        return _fail(INVALID_BUDGET, 'Unsupported currency')

    # 10. all passed
    return TravelOutput(
        status=Status.SUCCESS, error_code=ErrorCode.OK,
        route=[], stops=[], summary={}, budget_expansion={}, diff=None
    )

def _fail(code: ErrorCode, msg: str) -> TravelOutput:
    return TravelOutput(
        status=Status.FAILED, error_code=code, error_message=msg,
        route=[], stops=[], summary={}, budget_expansion={}, diff=None
    )
